    # Execute the conversion command
    result = subprocess.run(command, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
    
    if result.returncode != 0:
        raise Exception(f"Conversion failed: {result.stderr}")
    
    # Determine the generated output file name.
    # LibreOffice will name the converted file based on the input file's base name with new extension.
    base_name = os.path.splitext(os.path.basename(input_file))[0]
    # If conversion_format has a colon, take the first part as the extension.
    ext = conversion_format.split(":")[0]
    generated_file = os.path.join(output_dir, base_name + '.' + ext)
    
    # If the generated file name is not the desired output file, rename it.
    if os.path.abspath(generated_file) != os.path.abspath(output_file):
        if os.path.exists(output_file):
            os.remove(output_file)
        shutil.move(generated_file, output_file)

